#include <Wire.h>
#include <Adafruit_MAX31865.h>
#include <SD.h>
#define MAX_CS 8
#define HEATER_PIN 9
#define SD_CS 10
#define SUPPLY_V 12.0f
#define HEATER_R 14.4f
#define MASS_G 500.0f
#define Cv_VESSEL 120.0f
#define PULSE_MS 60000UL
#define BASELINE_MS 120000UL
Adafruit_MAX31865 rtd(MAX_CS); File lg;
float g_T0=0;
bool pulseDone=false, resultLogged=false;
unsigned long phaseStart=0;
float heat_capacity_calc(float T0,float T1,float V,float R,unsigned long dur,float m,float Cv){
  float Q=(V/R)*V*(dur/1000.0f);
  float dT=T1-T0;
  if(dT<=0||m<=0) return -1.0f;
  return (Q-Cv*dT)/m/dT;
}
void initHardware(){
  rtd.begin(MAX31865_3WIRE); pinMode(HEATER_PIN,OUTPUT);
  SD.begin(SD_CS); lg=SD.open("cp.csv",FILE_WRITE);
  if(lg) lg.println("t_s,T_C,phase");
  Serial.begin(9600); phaseStart=millis();
}
float readPT100Temperature(){ return rtd.temperature(100,430.0f); }
void logTempSD(unsigned long t, float T, const char* phase){
  if(lg){lg.print(t);lg.print(',');lg.print(T,3);lg.print(',');lg.println(phase);lg.flush();}
}
void checkFaultSafety(float T){
  if(T>90.0f){digitalWrite(HEATER_PIN,LOW);Serial.println("FAULT:OVERTEMP");while(1);}
}
void setup(){ initHardware(); }
void loop(){
  static unsigned long prev=0; unsigned long now=millis();
  if(now-prev<500) return; prev=now;
  float T=readPT100Temperature(); checkFaultSafety(T);
  if(!pulseDone && now-phaseStart<BASELINE_MS){
    logTempSD(now/1000,T,"baseline");
    if(now-phaseStart>BASELINE_MS-1000) g_T0=T;
  } else if(!pulseDone){
    digitalWrite(HEATER_PIN,HIGH); logTempSD(now/1000,T,"heating");
    if(now-phaseStart>BASELINE_MS+PULSE_MS){
      digitalWrite(HEATER_PIN,LOW); pulseDone=true;
    }
  } else if(!resultLogged){
    logTempSD(now/1000,T,"cooling");
    if(now-phaseStart>BASELINE_MS+PULSE_MS+60000UL){
      float Cp=heat_capacity_calc(g_T0,T,SUPPLY_V,HEATER_R,PULSE_MS,MASS_G,Cv_VESSEL);
      Serial.print("Cp=");Serial.print(Cp,4);Serial.println("J/gK");
      if(lg){lg.print("Cp_JgK=");lg.println(Cp,4);lg.close();}
      resultLogged=true;
    }
  }
}
